        start, end = move_input.split('-')
        start = ord(start[0]) - 97, int(start[1]) - 1
        end = ord(end[0]) - 97, int(end[1]) - 1
        if self.is_valid_move(start, end):
            self.apply_move(start, end)
            self.current_player = Player('red' if self.current_player.color == 'black' else 'black')
        else:
            print("Invalid move. Try again.")

    def is_valid_move(self, start, end):
        piece = self.board.board[start[0]][start[1]]
        if not piece or piece.color != self.current_player.color:
            return False
        # Add more rules here for capturing and kinging
        return True

    def apply_move(self, start, end):
        piece = self.board.board[start[0]][start[1]]
        self.board.board[end[0]][end[1]] = piece
        self.board.board[start[0]][start[1]] = None

